-- Job orders import from Production Report FY2026_Q1.xlsx
-- Hyderabad plant, Apr-Jun 2026. 2072 job orders aggregated from
-- 10055 production line items (avg 4.9 lines/job order).
--
-- customer_id is set ONLY where customer_name exactly matches (case/whitespace
-- normalized) an existing customers.name -- 598 of 2072
-- job orders (29%). The rest keep customer_name
-- as text with customer_id = NULL, per the user's explicit instruction: match by
-- name only (not code -- this report is from a different source system), and
-- don't guess on the ~54% that don't exactly match (branch-suffix variants like
-- "BAJAJ FINANCE LIMITED" vs "...- SIRSA", or naming differences like "Pvt Ltd"
-- vs "PRIVATE LIMITED", some even inconsistent within this file itself).
--
-- status is inferred from the source's single-letter Job Status code:
-- 'C' -> 'Completed', 'I' -> 'In Progress'. The column is literally named
-- "Job Status (Lost Hold transfer)", implying more codes (L/H/T?) exist in
-- other exports that don't appear in this one (only C and I are present here,
-- 10,051 and 4 rows respectively) -- this mapping is inferred, not confirmed.
--
-- total_value = sum over this job order's lines of (Sqft x Rate) for lines
-- priced by Sqft, or (Qty x Rate) for lines priced by Qty (41 lines of 10,055
-- have neither Price Type set and contribute 0 -- flagged, not guessed).

insert into job_orders
